PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE books (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  author TEXT NOT NULL,
  coverUrl TEXT,
  status TEXT DEFAULT 'UNREAD', -- 状态：UNREAD (待读), READING (在读), FINISHED (已读完)
  startTime TEXT,
  endTime TEXT,
  rating INTEGER DEFAULT 0,
  tags TEXT DEFAULT '[]',       -- SQLite 没有数组格式，我们用 JSON 字符串存标签
  addedAt DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE excerpts (
  id TEXT PRIMARY KEY,
  bookId TEXT NOT NULL,
  content TEXT NOT NULL,
  createdAt DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (bookId) REFERENCES books(id) ON DELETE CASCADE
);
CREATE TABLE reading_logs (
  id TEXT PRIMARY KEY,              -- 唯一流水号
  date TEXT NOT NULL,               -- 打卡日期，格式 'YYYY-MM-DD' (例如 '2026-03-26')
  book_id TEXT,                     -- 关联的书籍 ID (可选，预留给未来“精细化打卡”)
  action_type TEXT NOT NULL,        -- 触发动作：'MANUAL' (手动打卡), 'EXCERPT' (写摘录自动打卡)
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (book_id) REFERENCES books(id) ON DELETE SET NULL
);
CREATE UNIQUE INDEX idx_reading_logs_date ON reading_logs(date);
